function _cancelOrder(address nftAddress, uint256 assetId) internal returns (Order memory) {
  address sender = _msgSender();
  Order memory order = orderByAssetId[nftAddress][assetId];

  require(order.id != 0, "MarketplaceV2#_cancelOrder: INVALID_ORDER");
  require(order.seller == sender || sender == owner(), "MarketplaceV2#_cancelOrder: UNAUTHORIZED_USER");

  bytes32 orderId = order.id;
  address orderSeller = order.seller;
  address orderNftAddress = order.nftAddress;
  delete orderByAssetId[nftAddress][assetId];

  emit OrderCancelled(
    orderId,
    assetId,
    orderSeller,
    orderNftAddress
  );

  return order;
}

function migrate(address _oldBurner) external {
    if (msg.sender != address(LIDO)) revert OnlyLidoCanMigrate();
    if (_oldBurner == address(0)) revert ZeroAddress("_oldBurner");
    _checkContractVersion(1);
    if (!_storageV3Upgrade().isMigrationAllowed) revert MigrationNotAllowedOrAlreadyMigrated();
    _storageV3Upgrade().isMigrationAllowed = false;

    IBurner oldBurner = IBurner(_oldBurner);
    Storage storage $ = _storage();
    $.totalCoverSharesBurnt = oldBurner.getCoverSharesBurnt();
    $.totalNonCoverSharesBurnt = oldBurner.getNonCoverSharesBurnt();
    (uint256 coverShares, uint256 nonCoverShares) = oldBurner.getSharesRequestedToBurn();
    $.coverSharesBurnRequested = coverShares;
    $.nonCoverSharesBurnRequested = nonCoverShares;
}

function _calculateFee() internal view returns (uint256 fee, int256 growth, uint256 abnormallyHighFeeThreshold) {
    VaultHub.Report memory report = latestReport();
    // we include quarantined value for fees as well
    uint256 quarantineValue = _lazyOracle().quarantineValue(address(_stakingVault()));
    uint256 totalValueAndQuarantine = uint256(report.totalValue) + quarantineValue;
    growth = int256(totalValueAndQuarantine) - report.inOutDelta;
    int256 unsettledGrowth = growth - settledGrowth;

    if (unsettledGrowth > 0) {
        fee = (uint256(unsettledGrowth) * feeRate) / TOTAL_BASIS_POINTS;
    }

    abnormallyHighFeeThreshold = (totalValueAndQuarantine * ABNORMALLY_HIGH_FEE_THRESHOLD_BP) / TOTAL_BASIS_POINTS;
}

function _postBurn(address owner, uint256[] calldata tokenIds, uint256[] calldata amounts) internal virtual {
    require(tokenIds.length > 0, "Invalid input");
    address extension = _tokensExtension[tokenIds[0]];
    for (uint256 i; i < tokenIds.length;) {
        require(_tokensExtension[tokenIds[i]] == extension, "Mismatched token originators");
        unchecked {
            ++i;
        }
    }
    // Callback to originating extension if needed
    if (extension != address(0)) {
        if (ERC165Checker.supportsInterface(extension, type(IERC1155CreatorExtensionBurnable).interfaceId)) {
            IERC1155CreatorExtensionBurnable(extension).onBurn(owner, tokenIds, amounts);
        }
    }
}

function _mintExtension(address to, string memory uri, uint80 data, uint256 tokenId)
        internal
        virtual
        returns (uint256)
    {
        if (tokenId == 0) {
            ++_tokenCount;
            tokenId = _tokenCount;
        }

        _checkMintPermissions(to, tokenId);
        // Call pre mint
        _preMintExtension(to, tokenId);

        _safeMint(to, tokenId, data << 16 | _extensionToIndex[msg.sender]);

        if (bytes(uri).length > 0) {
            _tokenURIs[tokenId] = uri;
        }

        return tokenId;
    }

function _approve(address to, uint256 tokenId, address auth, bool emitEvent) internal virtual {
    ERC721Storage storage $ = _getERC721Storage();
    // Avoid reading the owner unless necessary
    if (emitEvent || auth != address(0)) {
        address owner = _requireOwned(tokenId);

        // We do not use _isAuthorized because single-token approvals should not be able to call approve
        if (auth != address(0) && owner != auth && !isApprovedForAll(owner, auth)) {
            revert ERC721InvalidApprover(auth);
        }

        if (emitEvent) {
            emit Approval(owner, to, tokenId);
        }
    }

    $._tokenApprovals[tokenId] = to;
}

function _settleFeesFromHook(PoolKey calldata key, bytes32 positionKey)
        internal
        virtual
        returns (BalanceDelta withheldFees)
    {
        PoolId poolId = key.toId();

        withheldFees = getWithheldFees(poolId, positionKey);

        // Reset the `withheldFees`.
        _withheldFees[poolId][positionKey] = BalanceDeltaLibrary.ZERO_DELTA;

        // Settle the `withheldFees` for the liquidity position.
        if (withheldFees.amount0() > 0) {
            key.currency0.settle(poolManager, address(this), uint256(uint128(withheldFees.amount0())), true);
        }
        if (withheldFees.amount1() > 0) {
            key.currency1.settle(poolManager, address(this), uint256(uint128(withheldFees.amount1())), true);
        }
    }

function _beforeTokenTransfer(
    address operator,
    address from,
    address to,
    uint256[] memory ids,
    uint256[] memory amounts,
    bytes memory data
) internal virtual override {
    super._beforeTokenTransfer(operator, from, to, ids, amounts, data);

    if (from == address(0)) {
        for (uint256 i = 0; i < ids.length; ++i) {
            totalSupply[ids[i]] += amounts[i];
        }
    }

    if (to == address(0)) {
        for (uint256 i = 0; i < ids.length; ++i) {
            totalSupply[ids[i]] -= amounts[i];
        }
    }
}

function _depositRewardTokens(uint256 _amount) internal virtual {
    require(msg.sender == owner(), "Not authorized");

    address _rewardToken = rewardToken == CurrencyTransferLib.NATIVE_TOKEN ? nativeTokenWrapper : rewardToken;

    uint256 balanceBefore = IERC20(_rewardToken).balanceOf(address(this));
    CurrencyTransferLib.transferCurrencyWithWrapper(
        rewardToken,
        msg.sender,
        address(this),
        _amount,
        nativeTokenWrapper
    );
    uint256 actualAmount = IERC20(_rewardToken).balanceOf(address(this)) - balanceBefore;

    rewardTokenBalance += actualAmount;
}

function approveCurrencyForListing(
    uint256 _listingId,
    address _currency,
    uint256 _pricePerTokenInCurrency
) external onlyExistingListing(_listingId) onlyListingCreator(_listingId) {
    Listing memory listing = _directListingsStorage().listings[_listingId];
    require(
        _currency != listing.currency || _pricePerTokenInCurrency == listing.pricePerToken,
        "Marketplace: approving listing currency with different price."
    );
    require(
        _directListingsStorage().currencyPriceForListing[_listingId][_currency] != _pricePerTokenInCurrency,
        "Marketplace: price unchanged."
    );

    _directListingsStorage().currencyPriceForListing[_listingId][_currency] = _pricePerTokenInCurrency;

    emit CurrencyApprovedForListing(_listingId, _currency, _pricePerTokenInCurrency);
}

constructor(
    IUniversalRouter _uniswap,
    Permit2 _permit2,
    address _initialOperator,
    address _initialFeeDestination,
    IWrappedNativeCurrency _wrappedNativeCurrency
) {
    require(
        address(_uniswap) != address(0) &&
            address(_permit2) != address(0) &&
            address(_wrappedNativeCurrency) != address(0) &&
            _initialOperator != address(0) &&
            _initialFeeDestination != address(0),
        "invalid constructor parameters"
    );
    uniswap = _uniswap;
    permit2 = _permit2;
    wrappedNativeCurrency = _wrappedNativeCurrency;

    // Sets an initial operator to enable immediate payment processing
    feeDestinations[_initialOperator] = _initialFeeDestination;
}

function _checkOnERC721Received(address from, address to, uint256 tokenId, bytes memory _data)
        private returns (bool)
    {
        if (to.isContract()) {
            try IERC721Receiver(to).onERC721Received(_msgSender(), from, tokenId, _data) returns (bytes4 retval) {
                return retval == IERC721Receiver(to).onERC721Received.selector;
            } catch (bytes memory reason) {
                if (reason.length == 0) {
                    revert("ERC721: transfer to non ERC721Receiver implementer");
                } else {
                    // solhint-disable-next-line no-inline-assembly
                    assembly {
                        revert(add(32, reason), mload(reason))
                    }
                }
            }
        } else {
            return true;
        }
    }

function _pushLandId(uint256 estateId, uint256 landId) internal {
  require(exists(estateId), "The Estate id should exist");
  require(landIdEstate[landId] == 0, "The LAND is already owned by an Estate");
  require(registry.ownerOf(landId) == address(this), "The EstateRegistry cannot manage the LAND");

  estateLandIds[estateId].push(landId);

  landIdEstate[landId] = estateId;

  estateLandIndex[estateId][landId] = estateLandIds[estateId].length;

  address owner = ownerOf(estateId);
  _updateEstateLandBalance(address(registry), owner, 1);

  emit AddLand(estateId, landId);
}

constructor (
  address _owner,
  address _feesCollector,
  address _acceptedToken,
  IRoyaltiesManager _royaltiesManager,
  uint256 _feesCollectorCutPerMillion,
  uint256 _royaltiesCutPerMillion
)  {
  // EIP712 init
  _initializeEIP712('Decentraland Marketplace', '2');

  // Address init
  setFeesCollector(_feesCollector);
  setRoyaltiesManager(_royaltiesManager);

  // Fee init
  setFeesCollectorCutPerMillion(_feesCollectorCutPerMillion);
  setRoyaltiesCutPerMillion(_royaltiesCutPerMillion);

  require(_owner != address(0), "MarketplaceV2#constructor: INVALID_OWNER");
  transferOwnership(_owner);

  require(_acceptedToken.isContract(), "MarketplaceV2#constructor: INVALID_ACCEPTED_TOKEN");
  acceptedToken = IERC20(_acceptedToken);
}

function proveAndClaimWithResolver(
    bytes memory name,
    DNSSEC.RRSetWithSignature[] memory input,
    address resolver,
    address addr
) public override {
    (bytes32 rootNode, bytes32 labelHash, address owner) = _claim(
        name,
        input
    );
    if (msg.sender != owner) {
        revert PermissionDenied(msg.sender, owner);
    }
    ens.setSubnodeRecord(rootNode, labelHash, owner, resolver, 0);
    if (addr != address(0)) {
        if (resolver == address(0)) {
            revert PreconditionNotMet();
        }
        bytes32 node = keccak256(abi.encodePacked(rootNode, labelHash));
        // Set the resolver record
        AddrResolver(resolver).setAddr(node, addr);
    }
}

function initialize(
    address _delegationManager,
    address _inferenceTaskManager,
    address _modelRegistry
) public initializer {
    __Ownable_init();
    if (
        _delegationManager == address(0) ||
        _inferenceTaskManager == address(0) ||
        _modelRegistry == address(0)
    ) {
        revert ZeroAddress();
    }
    delegationManager = IDelegationManager(_delegationManager);
    inferenceTaskManager = IInferenceTaskManager(_inferenceTaskManager);
    modelRegistry = ModelRegistry(_modelRegistry);
    nextNodeId = 1;
}

function findLowerBound(uint256[] storage _array, uint256 _val) internal view returns (uint256) {
    uint256 len = _array.length;
    if (len == 0) {
        return 0;
    }

    if (_array[len - 1] <= _val) {
        return len - 1;
    }

    uint256 upperIdx = _array.findUpperBound(_val);

    // we already checked the last element above so the upper will always be inside the array
    assert(upperIdx < len);

    // the exact value we were searching is in the array
    if (_array[upperIdx] == _val) {
        return upperIdx;
    }

    // a 0 idx means that the first elem is already higher than the searched value (and not equal, checked above)
    if (upperIdx == 0) {
        return len;
    }

    // the element at upperIdx is the first element higher than the value we want, so return the previous element
    return upperIdx - 1;
}

function _countVote(
    uint256 _proposalId,
    address _account,
    uint8 _supportInt,
    uint256 _weight,
    bytes memory // params
) internal virtual override {
    if (_supportInt > uint8(VoteType.Abstain)) {
        revert InvalidVoteType(_supportInt);
    }
    VoteType support = VoteType(_supportInt);

    ProposalTally storage tally = _proposalTallies[_proposalId];
    ProposalVoterState storage voter = tally.voters[_account];

    if (voter.hasVoted) {
        revert VoteAlreadyCast();
    }
    voter.hasVoted = true;
    voter.support = support;

    _weight = _handleVoteOverrides(_proposalId, tally, voter, _account, _weight);

    if (support == VoteType.Against) {
        tally.againstVotes += _weight;
    } else if (support == VoteType.For) {
        tally.forVotes += _weight;
    } else {
        tally.abstainVotes += _weight;
    }
}

function _getCreatorRecipientAndCalculateFeeAmount(
    address collection,
    uint256 price,
    uint256[] memory itemIds
) private view returns (address creator, uint256 creatorFeeAmount) {
    if (address(creatorFeeManager) != address(0)) {
        (creator, creatorFeeAmount) = creatorFeeManager.viewCreatorFeeInfo(collection, price, itemIds);

        if (creator == address(0)) {
            // If recipient is null address, creator fee is set to 0
            creatorFeeAmount = 0;
        } else if (creatorFeeAmount * ONE_HUNDRED_PERCENT_IN_BP > (price * uint256(maxCreatorFeeBp))) {
            // If creator fee is higher than tolerated, it reverts
            revert CreatorFeeBpTooHigh();
        }
    }
}

function calculatePurchaseReturn(uint256 _supply, uint256 _connectorBalance, uint32 _connectorWeight, uint256 _depositAmount) public view returns (uint256) {
    // validate input
    require(_supply > 0 && _connectorBalance > 0 && _connectorWeight > 0 && _connectorWeight <= MAX_WEIGHT);

    // special case for 0 deposit amount
    if (_depositAmount == 0)
        return 0;

    // special case if the weight = 100%
    if (_connectorWeight == MAX_WEIGHT)
        return safeMul(_supply, _depositAmount) / _connectorBalance;

    uint256 result;
    uint8 precision;
    uint256 baseN = safeAdd(_depositAmount, _connectorBalance);
    (result, precision) = power(baseN, _connectorBalance, _connectorWeight, MAX_WEIGHT);
    uint256 temp = safeMul(_supply, result) >> precision;
    return temp - _supply;
}

function claimFailedDeposit(
    address _depositSender,
    address _l1Token,
    bytes32 _l2TxHash,
    uint256 _l2BatchNumber,
    uint256 _l2MessageIndex,
    uint16 _l2TxNumberInBatch,
    bytes32[] calldata _merkleProof
) external nonReentrant {
    uint256 amount = depositAmount[_depositSender][_l1Token][_l2TxHash];
    // empty deposit
    if (amount == 0) {
        revert EmptyDeposit();
    }
    delete depositAmount[_depositSender][_l1Token][_l2TxHash];

    L1_NULLIFIER.claimFailedDepositLegacyErc20Bridge({
        _depositSender: _depositSender,
        _l1Token: _l1Token,
        _amount: amount,
        _l2TxHash: _l2TxHash,
        _l2BatchNumber: _l2BatchNumber,
        _l2MessageIndex: _l2MessageIndex,
        _l2TxNumberInBatch: _l2TxNumberInBatch,
        _merkleProof: _merkleProof
    });
    emit ClaimedFailedDeposit(_depositSender, _l1Token, amount);
}

function _validateMethods(bytes calldata _terms, bytes calldata _executionCallData) private pure {
    (,, bytes calldata callData_) = _executionCallData.decodeSingle();

    require(callData_.length >= 4, "AllowedMethodsEnforcer:invalid-execution-data-length");

    bytes4 targetSig_ = bytes4(callData_[0:4]);
    bytes4[] memory allowedSignatures_ = getTermsInfo(_terms);
    uint256 allowedSignaturesLength_ = allowedSignatures_.length;

    for (uint256 i = 0; i < allowedSignaturesLength_; ++i) {
        if (targetSig_ == allowedSignatures_[i]) {
            return;
        }
    }
    revert("AllowedMethodsEnforcer:method-not-allowed");
}

function getAddressNFTs(address userAddress) public view override returns (uint256[] memory NFTs, uint256 numberOfActive) {

    uint256 numberOfTokens = balanceOf(userAddress);

    numberOfActive = 0;
    uint256[] memory temp = new uint256[](numberOfTokens);
    for (uint256 x = 0; x < numberOfTokens; x++) {
        if (!accountLiquidated(tokenOfOwnerByIndex(userAddress, x))) {
            temp[numberOfActive] = tokenOfOwnerByIndex(userAddress, x);
            numberOfActive++;
        }
    }

    NFTs = new uint256[](numberOfActive);
    for (uint256 x = 0; x < numberOfActive; x++) {
        NFTs[x] = temp[x];
    }

    return (NFTs, numberOfActive);
}

function _setMarketBorrowCaps(
    MToken[] calldata mTokens,
    uint[] calldata newBorrowCaps
) external {
    require(
        msg.sender == admin || msg.sender == borrowCapGuardian,
        "only admin or borrow cap guardian can set borrow caps"
    );

    uint numMarkets = mTokens.length;
    uint numBorrowCaps = newBorrowCaps.length;

    require(
        numMarkets != 0 && numMarkets == numBorrowCaps,
        "invalid input"
    );

    for (uint i = 0; i < numMarkets; i++) {
        borrowCaps[address(mTokens[i])] = newBorrowCaps[i];
        emit NewBorrowCap(mTokens[i], newBorrowCaps[i]);
    }
}

constructor(
    address _inbox,
    address _checkpointTracker,
    address _initialProver,
    uint96 _initialFee,
    uint256 _initialDeposit
) {
    require(_inbox != address(0), ZeroAddress());
    require(_checkpointTracker != address(0), ZeroAddress());
    require(_initialProver != address(0), ZeroAddress());

    inbox = IInbox(_inbox);
    checkpointTracker = ICheckpointTracker(_checkpointTracker);

    // Close the first period so every period has a previous one (and an implicit start timestamp)
    // The initial fee and prover will take effect in the block after this one
    _deposit(_initialProver, _initialDeposit);
    _claimProvingVacancy(_initialFee, _initialProver);
}

function _requestRedeem(
    uint256 shares,
    address controller,
    address owner,
    uint256 requestId
) internal virtual returns (uint256) {
    require(_isRedeemAsync(), ERC7540SyncRedeem());

    address sender = _msgSender();
    if (owner != sender && !isOperator(owner, sender)) {
        _spendAllowance(owner, sender, shares);
    }
    if (_redeemShareDestination() == address(0)) {
        _totalPendingRedeemShares += shares;
        _burn(owner, shares);
    } else {
        _transfer(owner, _redeemShareDestination(), shares);
    }

    emit RedeemRequest(controller, owner, requestId, _msgSender(), shares);
    return requestId;
}

constructor(IERC7984ERC20Wrapper fromToken_, IERC7984ERC20Wrapper toToken_) {
    require(
        ERC165Checker.supportsInterface(address(fromToken_), type(IERC7984ERC20Wrapper).interfaceId),
        InvalidWrapperToken(address(fromToken_))
    );
    require(
        ERC165Checker.supportsInterface(address(toToken_), type(IERC7984ERC20Wrapper).interfaceId),
        InvalidWrapperToken(address(toToken_))
    );
    require(fromToken_.underlying() != toToken_.underlying(), DuplicateUnderlyingTokens());

    _fromToken = fromToken_;
    _toToken = toToken_;
    _currentBatchId = 1;

    SafeERC20.forceApprove(IERC20(fromToken().underlying()), address(fromToken()), type(uint256).max);
    SafeERC20.forceApprove(IERC20(toToken().underlying()), address(toToken()), type(uint256).max);
}

function _moveDelegateVotes(address from, address to, euint64 amount) internal virtual {
    CheckpointsConfidential.TraceEuint64 storage store;
    if (from != to && FHE.isInitialized(amount)) {
        if (from != address(0)) {
            store = _delegateCheckpoints[from];
            euint64 newValue = store.latest().sub(amount);
            newValue.allowThis();
            euint64 oldValue = _push(store, newValue);
            emit DelegateVotesChanged(from, oldValue, newValue);
        }
        if (to != address(0)) {
            store = _delegateCheckpoints[to];
            euint64 newValue = store.latest().add(amount);
            newValue.allowThis();
            euint64 oldValue = _push(store, newValue);
            emit DelegateVotesChanged(to, oldValue, newValue);
        }
    }
}

function createOfferMinimal(address _tokenContract, uint256 _tokenId) external payable nonReentrant returns (uint256) {
    uint256 _offerAmount = msg.value;
    weth.deposit{value: msg.value}();
    weth.transferFrom(address(this), msg.sender, _offerAmount);

    if (weth.allowance(msg.sender, address(erc20TransferHelper)) < _offerAmount) revert INSUFFICIENT_ALLOWANCE();
    if (!erc721TransferHelper.isModuleApproved(msg.sender)) revert MODULE_NOT_APPROVED();

    ++offerCount;

    StoredOffer storage offer = offers[_tokenContract][_tokenId][offerCount];
    offer.amount = _offerAmount;
    offer.maker = msg.sender;
    offer.features = 0;

    offersForNFT[_tokenContract][_tokenId].push(offerCount);
    emit OfferCreated(_tokenContract, _tokenId, offerCount, _getFullOffer(offer));
    return offerCount;
}

function _remove(
    _PackedDoublyLinkedList storage self,
    bytes16 value
) private returns (bool status) {
    if (_contains(self, value)) {
        (bytes16 prevValue, bytes16 nextValue) = _adjacent(self, value);

        bytes32 prevLinks = self._links[prevValue];
        self._links[prevValue] =
            (prevLinks & MASK_PREV) | _formatLinks(0, nextValue);

        bytes32 nextLinks = self._links[nextValue];
        self._links[nextValue] =
            (nextLinks & MASK_NEXT) | _formatLinks(prevValue, 0);

        delete self._links[value];
        status = true;
    }
}
